/* ─── PAGE LISTE PROFILS ─────────────────────────────────────── */
function PageProfils({ filtre, setPage }) {
  const [metier,setMetier] = useState(filtre?.metier||"");
  const [ville,setVille]   = useState(filtre?.ville||"");
  const [dispo,setDispo]   = useState(filtre?.dispo||false);
  const [q,setQ]           = useState("");

  const liste = DB.profils.filter(p=>{
    if(metier && p.metier!==metier) return false;
    if(ville  && p.ville !==ville)  return false;
    if(dispo  && !p.dispo)          return false;
    if(q && !p.nom.toLowerCase().includes(q.toLowerCase())
         && !p.metier.toLowerCase().includes(q.toLowerCase())) return false;
    return true;
  });

  return (
    <div style={{maxWidth:860,margin:"0 auto",padding:"32px 20px"}}>
      <p className="section-label">Base de données</p>
      <h1 className="section-title" style={{marginBottom:6}}>Les profils</h1>
      <p style={{color:"#718096",fontSize:14,marginBottom:24}}>
        {liste.length} profil(s) — cliquez pour voir la fiche complète
      </p>

      {/* Filtres */}
      <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:16,
        padding:"14px 18px",marginBottom:22,
        display:"flex",gap:10,flexWrap:"wrap",alignItems:"center"}}>
        <input value={q} onChange={e=>setQ(e.target.value)}
          placeholder="🔍  Rechercher un nom..."
          className="field" style={{flex:1,minWidth:160}}/>
        <select value={metier} onChange={e=>setMetier(e.target.value)}
          className="field" style={{width:"auto",cursor:"pointer"}}>
          <option value="">Tous les métiers</option>
          {METIERS.map(m=><option key={m}>{m}</option>)}
        </select>
        <select value={ville} onChange={e=>setVille(e.target.value)}
          className="field" style={{width:"auto",cursor:"pointer"}}>
          <option value="">Toutes les régions</option>
          <optgroup label="— 14 Régions —">
            {VILLES.slice(0,14).map(v=><option key={v}>{v}</option>)}
          </optgroup>
          <optgroup label="— Autres villes —">
            {VILLES.slice(14).map(v=><option key={v}>{v}</option>)}
          </optgroup>
        </select>
        <label style={{display:"flex",alignItems:"center",gap:7,
          fontSize:13,cursor:"pointer",fontWeight:500,color:"#374151"}}>
          <input type="checkbox" checked={dispo} onChange={e=>setDispo(e.target.checked)}
            style={{width:16,height:16,accentColor:"#1a3a8c"}}/>
          Disponibles
        </label>
      </div>

      {liste.length===0 ? (
        <div style={{textAlign:"center",padding:"60px 20px",color:"#718096"}}>
          <div style={{fontSize:56,marginBottom:16}}>👥</div>
          <p style={{fontSize:16,fontWeight:600,color:"#374151",marginBottom:8}}>
            {DB.profils.length===0
              ? "Aucun profil enregistré pour l'instant."
              : "Aucun résultat pour ces critères."}
          </p>
          {DB.profils.length===0 && (
            <p style={{fontSize:13,marginBottom:20,color:"#718096"}}>
              Soyez le premier à rejoindre la plateforme !
            </p>
          )}
          {DB.profils.length===0 && (
            <button className="btn-outline" onClick={()=>setPage("accueil")}
              style={{margin:"0 auto"}}>
              👤 S'inscrire comme prestataire
            </button>
          )}
        </div>
      ) : (
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {liste.map(p=>(
            <div key={p.id} className="profil-row"
              onClick={()=>setPage({nom:"profil",data:p})}>
              <div style={{fontSize:50,lineHeight:1,flexShrink:0}}>{p.avatar}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:17,color:"#1a202c",marginBottom:3}}>{p.nom}</div>
                <div style={{fontSize:13,color:"#4a5568",marginBottom:6}}>
                  <span style={{fontWeight:600,color:"#2756c5"}}>{p.metier}</span>
                  &nbsp;·&nbsp;{p.ville}
                  &nbsp;·&nbsp;{p.exp} an{p.exp>1?"s":""} d'exp.
                </div>
                <Stars note={p.note}/>
              </div>
              <Dispo v={p.dispo}/>
              <span style={{color:"#2756c5",fontSize:24,flexShrink:0}}>›</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ─── PAGE PROFIL INDIVIDUEL ─────────────────────────────────── */
function PageProfil({ profil, setPage }) {
  const [msg,setMsg] = useState("");
  const [ok,setOk]   = useState(false);

  const envoyer = () => {
    if(!msg.trim()) return;
    DB.messages.push({id:Date.now()+"",profilId:profil.id,msg,date:new Date().toISOString()});
    setMsg(""); setOk(true);
    setTimeout(()=>setOk(false),3000);
  };

  return (
    <div style={{maxWidth:640,margin:"0 auto",padding:"28px 20px"}}>
      <button onClick={()=>setPage("profils")}
        style={{background:"none",border:"none",color:"#2756c5",
          cursor:"pointer",fontSize:14,fontWeight:600,
          display:"flex",alignItems:"center",gap:6,
          marginBottom:20,padding:0}}>
        ← Retour à la liste
      </button>

      <div style={{background:"#fff",borderRadius:24,border:"1px solid #e2e8f0",
        overflow:"hidden",boxShadow:"0 8px 40px rgba(26,58,140,0.1)"}}>

        {/* EN-TÊTE */}
        <div style={{background:"linear-gradient(135deg,#0b1f5c,#1a3a8c,#2756c5)",
          padding:"38px 28px",color:"#fff",textAlign:"center",
          position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",top:-30,right:-30,width:130,height:130,
            borderRadius:"50%",background:"rgba(255,255,255,0.06)",pointerEvents:"none"}}/>
          <div style={{fontSize:84,lineHeight:1,marginBottom:14}}>{profil.avatar}</div>
          <h2 style={{fontFamily:"'Playfair Display',serif",
            fontSize:26,fontWeight:900,margin:"0 0 6px"}}>{profil.nom}</h2>
          <div style={{opacity:.85,fontSize:15,marginBottom:12}}>
            {profil.metier} &nbsp;·&nbsp; 📍 {profil.ville}
          </div>
          <div style={{display:"flex",justifyContent:"center",marginBottom:14}}>
            <Stars note={profil.note}/>
          </div>
          <Dispo v={profil.dispo}/>
        </div>

        {/* CORPS */}
        <div style={{padding:"26px 28px"}}>

          {/* Stats */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",
            gap:12,marginBottom:22}}>
            {[
              ["🎂","Âge",profil.age+" ans"],
              ["📅","Expérience",profil.exp+" an"+(profil.exp>1?"s":"")],
              ["📍","Région",profil.ville],
            ].map(([e,l,v],i)=>(
              <div key={i} style={{background:"#f8faff",border:"1px solid #e8edf5",
                borderRadius:14,padding:"14px 10px",textAlign:"center"}}>
                <div style={{fontSize:22,marginBottom:5}}>{e}</div>
                <div style={{fontSize:11,color:"#718096",marginBottom:3}}>{l}</div>
                <div style={{fontSize:14,fontWeight:700,color:"#1a202c"}}>{v}</div>
              </div>
            ))}
          </div>

          {/* Description */}
          <div style={{marginBottom:20}}>
            <div style={{fontSize:12,fontWeight:700,color:"#1a3a8c",
              textTransform:"uppercase",letterSpacing:1.5,marginBottom:10}}>
              À propos
            </div>
            <p style={{color:"#4a5568",lineHeight:1.8,fontSize:14,
              background:"#fafbfc",borderRadius:12,
              padding:"14px 16px",border:"1px solid #e2e8f0",margin:0}}>
              {profil.desc}
            </p>
          </div>

          {/* Téléphone */}
          <div style={{background:"linear-gradient(135deg,#eef2ff,#f0f4ff)",
            border:"1px solid #c7d2fe",borderRadius:14,
            padding:"16px 18px",marginBottom:22,
            display:"flex",alignItems:"center",gap:14}}>
            <div style={{width:46,height:46,
              background:"linear-gradient(135deg,#1a3a8c,#2756c5)",
              borderRadius:12,display:"flex",alignItems:"center",
              justifyContent:"center",fontSize:22,flexShrink:0}}>📞</div>
            <div>
              <div style={{fontSize:12,color:"#6b7280",marginBottom:3}}>Numéro de téléphone</div>
              <div style={{fontSize:20,fontWeight:700,color:"#1a3a8c"}}>{profil.tel}</div>
            </div>
          </div>

          {/* Message */}
          <div style={{fontSize:12,fontWeight:700,color:"#1a3a8c",
            textTransform:"uppercase",letterSpacing:1.5,marginBottom:10}}>
            Envoyer un message
          </div>
          <Toast msg={ok?"Message envoyé avec succès !":""}/>
          <textarea value={msg} onChange={e=>setMsg(e.target.value)}
            className="field"
            placeholder={"Bonjour "+profil.nom.split(" ")[0]+", je souhaite vous contacter pour..."}
            rows={3} style={{resize:"none",marginBottom:12}}/>
          <button className="btn-primary" onClick={envoyer}>
            ✉️ Envoyer le message
          </button>
        </div>
      </div>
    </div>
  );
}

/* ─── PAGE DEMANDE ───────────────────────────────────────────── */
function PageDemande() {
  const v0={nom:"",tel:"",ville:"Dakar",metier:"Gardien",budget:"",msg:""};
  const [f,setF]   = useState(v0);
  const [ok,setOk] = useState(false);
  const set=(k,v)=>setF(x=>({...x,[k]:v}));

  const submit=()=>{
    if(!f.nom||!f.tel||!f.msg){alert("Remplissez les champs obligatoires.");return;}
    DB.demandes.push({id:Date.now()+"",date:new Date().toISOString(),...f});
    setOk(true);
    setTimeout(()=>{setOk(false);setF(v0);},3500);
  };

  return (
    <div style={{maxWidth:560,margin:"0 auto",padding:"32px 20px"}}>
      <p className="section-label">Recrutement</p>
      <h1 className="section-title" style={{marginBottom:8}}>Déposer une demande</h1>
      <p style={{color:"#718096",fontSize:14,marginBottom:26,lineHeight:1.65}}>
        Décrivez votre besoin et nous vous proposerons des profils adaptés sous 24h.
      </p>
      <Toast msg={ok?"Demande envoyée ! Nous vous répondrons sous 24h.":""}/>
      <div style={{background:"#fff",borderRadius:20,border:"1px solid #e2e8f0",
        padding:26,boxShadow:"0 4px 20px rgba(26,58,140,0.07)"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}}>
          <div>
            <label>Votre nom *</label>
            <input className="field" value={f.nom} onChange={e=>set("nom",e.target.value)} placeholder="Nom complet"/>
          </div>
          <div>
            <label>Téléphone *</label>
            <input className="field" value={f.tel} onChange={e=>set("tel",e.target.value)} placeholder="7X XXX XX XX"/>
          </div>
          <div>
            <label>Région / Ville</label>
            <select className="field" value={f.ville} onChange={e=>set("ville",e.target.value)} style={{cursor:"pointer"}}>
              <optgroup label="— 14 Régions —">
                {VILLES.slice(0,14).map(v=><option key={v}>{v}</option>)}
              </optgroup>
              <optgroup label="— Autres villes —">
                {VILLES.slice(14).map(v=><option key={v}>{v}</option>)}
              </optgroup>
            </select>
          </div>
          <div>
            <label>Personnel recherché</label>
            <select className="field" value={f.metier} onChange={e=>set("metier",e.target.value)} style={{cursor:"pointer"}}>
              {METIERS.map(m=><option key={m}>{m}</option>)}
            </select>
          </div>
        </div>
        <div style={{marginBottom:14}}>
          <label>Budget mensuel (FCFA)</label>
          <input className="field" value={f.budget} onChange={e=>set("budget",e.target.value)} placeholder="Ex: 80 000 FCFA / mois"/>
        </div>
        <div style={{marginBottom:20}}>
          <label>Décrivez vos besoins *</label>
          <textarea className="field" rows={4} value={f.msg} onChange={e=>set("msg",e.target.value)}
            placeholder="Horaires, tâches spécifiques, conditions de logement..." style={{resize:"none"}}/>
        </div>
        <button className="btn-primary" onClick={submit}>📋 Envoyer ma demande</button>
      </div>
    </div>
  );
}

