/* ─── PAGE ADMIN ─────────────────────────────────────────────── */
function PageAdmin() {
  const [onglet,setOnglet] = useState("profils");
  const [,maj] = useState(0);

  const suppProfil = id=>{
    if(!confirm("Supprimer ce profil ?")) return;
    DB.profils = DB.profils.filter(p=>p.id!==id); maj(n=>n+1);
  };
  const toggleDispo = id=>{
    const p=DB.profils.find(p=>p.id===id);
    if(p){p.dispo=!p.dispo;maj(n=>n+1);}
  };
  const suppDemande = id=>{
    DB.demandes=DB.demandes.filter(d=>d.id!==id); maj(n=>n+1);
  };

  const tabs=[
    {k:"profils", l:`Profils (${DB.profils.length})`},
    {k:"demandes",l:`Demandes (${DB.demandes.length})`},
    {k:"messages",l:`Messages (${DB.messages.length})`},
  ];

  return (
    <div style={{maxWidth:900,margin:"0 auto",padding:"32px 20px"}}>
      <p className="section-label">Tableau de bord</p>
      <h1 className="section-title" style={{marginBottom:24}}>Administration</h1>

      {/* Onglets */}
      <div style={{display:"flex",gap:4,background:"#e2e8f0",borderRadius:12,
        padding:4,marginBottom:22}}>
        {tabs.map(t=>(
          <button key={t.k} onClick={()=>setOnglet(t.k)} style={{
            flex:1,border:"none",borderRadius:9,padding:"10px 8px",
            fontSize:13,fontWeight:600,cursor:"pointer",
            background:onglet===t.k?"#fff":"transparent",
            color:onglet===t.k?"#1a3a8c":"#6b7280",
            boxShadow:onglet===t.k?"0 1px 4px rgba(0,0,0,0.1)":"none",
            transition:"all .15s",fontFamily:"'DM Sans',sans-serif"
          }}>{t.l}</button>
        ))}
      </div>

      {onglet==="profils" && (
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {DB.profils.length===0 && (
            <p style={{color:"#718096",textAlign:"center",padding:40}}>
              Aucun profil enregistré
            </p>
          )}
          {DB.profils.map(p=>(
            <div key={p.id} style={{background:"#fff",borderRadius:14,
              border:"1px solid #e2e8f0",padding:"12px 16px",
              display:"flex",gap:12,alignItems:"center"}}>
              <span style={{fontSize:34,flexShrink:0}}>{p.avatar}</span>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:14,color:"#1a202c"}}>{p.nom}</div>
                <div style={{fontSize:12,color:"#718096"}}>
                  {p.metier} · {p.ville} · {p.age} ans · {p.exp} ans exp.
                </div>
                <div style={{fontSize:12,color:"#2756c5",marginTop:2}}>{p.tel}</div>
              </div>
              <button onClick={()=>toggleDispo(p.id)} style={{
                background:p.dispo?"#dcfce7":"#fee2e2",
                color:p.dispo?"#16a34a":"#dc2626",
                border:"none",borderRadius:8,
                padding:"4px 10px",fontSize:11,
                fontWeight:700,cursor:"pointer",whiteSpace:"nowrap",
                fontFamily:"'DM Sans',sans-serif"
              }}>{p.dispo?"✓ Disponible":"✗ Occupé"}</button>
              <button onClick={()=>suppProfil(p.id)} style={{
                background:"#fee2e2",color:"#dc2626",border:"none",
                borderRadius:8,padding:"4px 10px",
                fontSize:11,cursor:"pointer",fontFamily:"'DM Sans',sans-serif"
              }}>✕ Supprimer</button>
            </div>
          ))}
        </div>
      )}

      {onglet==="demandes" && (
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {DB.demandes.length===0 && (
            <p style={{color:"#718096",textAlign:"center",padding:40}}>Aucune demande reçue</p>
          )}
          {DB.demandes.map(d=>(
            <div key={d.id} style={{background:"#fff",borderRadius:14,
              border:"1px solid #e2e8f0",padding:"14px 18px"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{fontWeight:700,fontSize:14,color:"#1a202c"}}>
                    {d.nom} — {d.tel}
                  </div>
                  <div style={{fontSize:12,color:"#718096",margin:"3px 0 6px"}}>
                    {d.metier} · {d.ville} {d.budget&&"· Budget: "+d.budget}
                  </div>
                  <p style={{fontSize:13,color:"#374151",lineHeight:1.6,margin:0}}>{d.msg}</p>
                </div>
                <button onClick={()=>suppDemande(d.id)} style={{
                  background:"#fee2e2",color:"#dc2626",border:"none",
                  borderRadius:8,padding:"4px 10px",fontSize:11,
                  cursor:"pointer",flexShrink:0,marginLeft:12,
                  fontFamily:"'DM Sans',sans-serif"
                }}>✕</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {onglet==="messages" && (
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {DB.messages.length===0 && (
            <p style={{color:"#718096",textAlign:"center",padding:40}}>Aucun message reçu</p>
          )}
          {DB.messages.map(m=>(
            <div key={m.id} style={{background:"#fff",borderRadius:14,
              border:"1px solid #e2e8f0",padding:"14px 18px"}}>
              {m.nom && (
                <div style={{fontWeight:700,fontSize:14,color:"#1a202c",marginBottom:3}}>
                  {m.nom} {m.email&&"— "+m.email}
                </div>
              )}
              <p style={{fontSize:13,color:"#374151",lineHeight:1.6,margin:"4px 0 4px"}}>{m.msg}</p>
              <div style={{fontSize:11,color:"#718096"}}>
                {new Date(m.date).toLocaleDateString("fr-FR",{
                  day:"2-digit",month:"long",year:"numeric",hour:"2-digit",minute:"2-digit"
                })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ─── APP ────────────────────────────────────────────────────── */
export default function App() {
  const [page,setPage] = useState("accueil");
  const cur = typeof page==="object" ? page.nom : page;

  return (
    <div style={{minHeight:"100vh",background:"#f0f4f9",fontFamily:"'DM Sans',sans-serif"}}>
      <InjectCSS/>
      <Navbar page={page} setPage={setPage}/>
      <main style={{minHeight:"calc(100vh - 60px - 58px)"}}>
        {cur==="accueil"  && <PageAccueil setPage={setPage}/>}
        {cur==="profils"  && <PageProfils filtre={typeof page==="object"?page.filtre:null} setPage={setPage}/>}
        {cur==="profil"   && typeof page==="object" && <PageProfil profil={page.data} setPage={setPage}/>}
        {cur==="demande"  && <PageDemande/>}
        {cur==="contact"  && <PageContact/>}
        {cur==="admin"    && <PageAdmin/>}
      </main>
      <footer style={{background:"linear-gradient(135deg,#0b1f5c,#1a3a8c)",
        color:"rgba(255,255,255,0.65)",padding:"18px 24px",textAlign:"center",fontSize:12}}>
        <div style={{display:"flex",justifyContent:"center",alignItems:"center",gap:10,marginBottom:5}}>
          <img src={LOGO} alt="Logo" style={{height:26,filter:"brightness(10)"}}/>
          <strong style={{color:"#fff",fontSize:14,fontFamily:"'Playfair Display',serif"}}>
            Jappo Domestique
          </strong>
        </div>
        🇸🇳 Plateforme de personnel de maison — Sénégal &nbsp;·&nbsp; © 2026 Jappo Domestique
      </footer>
    </div>
  );
}
